mapper.select:
 /* com.educare.edu.comn.mapper.CheckMapper.selectLctrePassCtgryYearCnt */
	select count(*) from t_lecture_stdnt
	where user_id = #{userId}
	and pass_yn = 'Y'
	and edu_seq in (select edu_seq from t_lecture tl where tl.detail_ctgry_seq = #{detailCtgrySeq} and substr(tl.edu_period_begin,1,4) = #{year}  )

 /* com.educare.edu.comn.mapper.CheckMapper.selectCountAssgnLectureRoom */
	select count(*) from t_lecture_time a
	where a.edu_dt = #{eduDt}
	and (
		(#{startTm} between a.start_tm and a.end_tm)
		or (#{endTm} between a.start_tm and a.end_tm)
	)
	and a.edu_seq in (select edu_seq from t_lecture where edu_seq = a.edu_seq and room_seq=#{roomSeq})
